namespace sv_5661c36220d448f9b10b0bd04e2a6ca4.Client.Services;

public interface IShipmentService
{
    Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

public sealed class ShipmentDetails
{
    public required string TrackingNumber { get; init; }
    public required string Status { get; init; }
    public required string Location { get; init; }
    public required DateTimeOffset EstimatedDelivery { get; init; }
    public required IReadOnlyList<StatusUpdate> StatusUpdates { get; init; }
}

public sealed class StatusUpdate
{
    public required DateTimeOffset Timestamp { get; init; }
    public required string Description { get; init; }
    public required string Location { get; init; }
}

using sv_5661c36220d448f9b10b0bd04e2a6ca4.Client.Services;

namespace sv_5661c36220d448f9b10b0bd04e2a6ca4.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-1001"] = new ShipmentDetails
        {
            TrackingNumber = "TRK-1001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 3, 17, 0, 0, TimeSpan.FromHours(-5)),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 26, 9, 0, 0, TimeSpan.FromHours(-5)), Description = "Package picked up", Location = "New York, NY" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 27, 14, 30, 0, TimeSpan.FromHours(-5)), Description = "Arrived at sorting facility", Location = "Philadelphia, PA" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 28, 8, 15, 0, TimeSpan.FromHours(-5)), Description = "Departed facility", Location = "Philadelphia, PA" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 29, 6, 45, 0, TimeSpan.FromHours(-5)), Description = "In transit", Location = "Chicago, IL" },
            ]
        },
        ["TRK-2002"] = new ShipmentDetails
        {
            TrackingNumber = "TRK-2002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 28, 12, 0, 0, TimeSpan.FromHours(-7)),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 24, 10, 0, 0, TimeSpan.FromHours(-7)), Description = "Package picked up", Location = "Seattle, WA" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 25, 16, 0, 0, TimeSpan.FromHours(-7)), Description = "Arrived at sorting facility", Location = "Portland, OR" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 27, 9, 20, 0, TimeSpan.FromHours(-7)), Description = "Out for delivery", Location = "San Francisco, CA" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 27, 14, 5, 0, TimeSpan.FromHours(-7)), Description = "Delivered", Location = "San Francisco, CA" },
            ]
        },
        ["TRK-3003"] = new ShipmentDetails
        {
            TrackingNumber = "TRK-3003",
            Status = "Label Created",
            Location = "Dallas, TX",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 5, 18, 0, 0, TimeSpan.FromHours(-5)),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 29, 1, 0, 0, TimeSpan.FromHours(-5)), Description = "Shipping label created", Location = "Dallas, TX" },
            ]
        },
    };

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"No shipment found for tracking number '{trackingNumber}'.");
    }
}

using System.Net;
using System.Net.Http.Json;

namespace sv_5661c36220d448f9b10b0bd04e2a6ca4.Client.Services;

public sealed class ShipmentHttpClient(HttpClient http) : IShipmentService
{
    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await http.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == HttpStatusCode.NotFound)
        {
            throw new KeyNotFoundException($"No shipment found for tracking number '{trackingNumber}'.");
        }

        response.EnsureSuccessStatusCode();

        return await response.Content.ReadFromJsonAsync<ShipmentDetails>(ct)
            ?? throw new InvalidOperationException("Received empty response from server.");
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_5661c36220d448f9b10b0bd04e2a6ca4.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

<h1>Shipment Tracker</h1>

@if (_loading)
{
    <div class="alert alert-info" role="status">
        <span class="spinner-border spinner-border-sm me-2" aria-hidden="true"></span>
        Loading shipment <strong>@TrackingNumber</strong>&hellip;
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p class="mb-2">@_errorMessage</p>
        <button class="btn btn-outline-danger btn-sm" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5 class="card-title">@_shipment.TrackingNumber</h5>
            <p><strong>Status:</strong> @_shipment.Status</p>
            <p><strong>Location:</strong> @_shipment.Location</p>
            <p><strong>Estimated Delivery:</strong> @_shipment.EstimatedDelivery.ToString("f")</p>
        </div>
    </div>

    <h4>Status Updates</h4>
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Time</th>
                <th>Description</th>
                <th>Location</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var update in _shipment.StatusUpdates)
            {
                <tr>
                    <td>@update.Timestamp.ToString("g")</td>
                    <td>@update.Description</td>
                    <td>@update.Location</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private ShipmentDetails? _shipment;
    private bool _loading;
    private string? _errorMessage;

    private CancellationTokenSource? _cts;

    protected override Task OnParametersSetAsync() => LoadShipmentAsync();

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request when the tracking number changes or on retry.
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _shipment = null;
        _errorMessage = null;
        _loading = true;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed — silently stop.
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
        }
    }

    private Task RetryAsync() => LoadShipmentAsync();

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

